const items = $input.all();
const base = items[0].json; // base for task info

let recipients = [];

// Task owner
if (base.task_owner_email) {
  recipients.push({
    email: base.task_owner_email,
    firstname: base.task_owner_firstname,
    lastname: base.task_owner_lastname,
  });
}

// Mentioned users (unique)
const mentionedUsersMap = new Map();
items.forEach(item => {
  const json = item.json;
  if (json.mentioned_user_email && !mentionedUsersMap.has(json.mentioned_user_email)) {
    mentionedUsersMap.set(json.mentioned_user_email, {
      email: json.mentioned_user_email,
      firstname: json.mentioned_user_firstname || '',
      lastname: json.mentioned_user_lastname || '',
    });
  }
});
recipients.push(...mentionedUsersMap.values());

// Build email items with milestone & project info
const emails = recipients.map(recipient => ({
  json: {
    task_id: base.task_id,
    task_title: base.task_title,
    task_created_at: base.task_created_at,
    task_due_date: base.task_due_date,
    milestone_id: base.milestone_id,
    milestone_title: base.milestone_title,
    project_id: base.project_id,
    project_title: base.project_title,
    comment_body: base.comment_body,
    commented_by_firstname: base.commented_by_firstname,
    commented_by_lastname: base.commented_by_lastname,
    recipient_email: recipient.email,
    recipient_firstname: recipient.firstname,
    recipient_lastname: recipient.lastname
  }
}));

return emails;

const items = $input.all();

// first item always contains task data
const taskData = items[0].json;

// collect mentioned user emails (if any)
const mentionedEmails = items
  .map(i => i.json.email)
  .filter(email => email && email.includes('@')); // removes null

// build recipient list
const recipients = [
  taskData.task_owner_email,
  ...mentionedEmails
];

// remove nulls + duplicates
const uniqueRecipients = [...new Set(recipients.filter(Boolean))];

return [{
  json: {
    task_id: taskData.task_id,
    task_title: taskData.task_title,
    comment_body: taskData.comment_body,
    all_recipients: uniqueRecipients
  }
}];

const items = [];

for (const item of $input.all()) {
  const emails = (item.json.observer_emails || '').split(',');
  const firstNames = (item.json.observer_first_names || '').split(',');
  const lastNames = (item.json.observer_last_names || '').split(',');

  for (let i = 0; i < emails.length; i++) {
    if (!emails[i]) continue;

    items.push({
      json: {
        ...item.json,
        observer_email: emails[i].trim(),
        observer_first_name: firstNames[i]?.trim(),
        observer_last_name: lastNames[i]?.trim()
      }
    });
  }
}

return items;
